insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('1-2 Switch', 20000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000000141/ed7d64a9ec942a31e364c16d9501628216f835539ee05d1ff510b270d50b3d3b', '1-2 Switch es un juego de fiesta para Nintendo Switch diseñado como un escaparate de las capacidades de los controladores Joy-Con, especialmente su tecnología de control de movimiento y vibración HD. ', 'https://www.youtube.com/watch?v=DpHDJRGuL7w', '1.4 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Advance Wars™ 1+2: Re-Boot Camp', 25000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000064132/cf6a52d93890df44059d7ba1376beec19155112c7b9cff000ba10eabea0f6ecd', 'Advance Wars 1+2: Re-Boot Camp es un remake táctico por turnos para Switch. Comanda ejércitos, usa CO Powers únicos y planifica tu estrategia en el campo de batalla en dos campañas clásicas totalmente rehechas. ¡Estrategia bélica a todo color!', 'https://www.youtube.com/watch?v=C35Xl270AvQ', '6.7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Alien Isolation', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000020818/12e8099c149a839a3a1e9255e65a9857629017fc6cd36e74cfc4a2f4f4c2e5c8', 'Alien: Isolation te sumerge en una aventura de terror y supervivencia. Juega como Amanda Ripley, eludiendo a un único, implacable y aterrador Xenomorfo. Usa tu ingenio y el sigilo para sobrevivir en la estación Sevastopol. Es la experiencia de terror definitiva en portátil.', 'https://www.youtube.com/watch?v=rwq-Msina10', '17.8 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Animal Crossing New Horizon', 14990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000027619/9989957eae3a6b545194c42fec2071675c34aadacd65e6b33fdfe7b3b6a86c3a', 'Animal Crossing: New Horizons te lleva a una isla desierta para comenzar una nueva vida. Pesca, atrapa bichos, decora, cultiva y crea tu propia comunidad paradisíaca. Personaliza todo a tu gusto y disfruta de un ritmo de vida relajado. ¡Tu isla, tus reglas!', 'https://www.youtube.com/watch?v=_3YNL0OWio0', '10.2 GB', true, 9990, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Arms', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000000392/0cfd031ae9dcca48aa6a6da6f0babbdd8c848b58a9c8178849dfee08f3edef33', 'ARMS es un dinámico juego de lucha donde los personajes usan puños extensibles. Combina estrategia, movimiento y reflejos en emocionantes batallas 3D. Elige tus puños (ARMS) y domina los diferentes estilos de combate. ¡Lanza golpes curvos y desata tu poder elástico!', 'https://www.youtube.com/watch?v=JiOAfYey5g4', '3.2 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Assassin''s Creed The Rebel Collection', 15000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000019188/28bf43d37e315a10c2ef5a518994d0bdc731837155177b6def5cbfbb39bf26ed', 'The Rebel Collection trae a Switch dos aventuras clásicas: Black Flag y Rogue. Navega por el Caribe como pirata (Edward Kenway) o cazador de asesinos (Shay Cormac). Disfruta de épicas batallas navales y explora vastos mundos abiertos. ¡El credo pirata te espera!', 'https://www.youtube.com/watch?v=69z9nLvIUSQ', '11.9 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Assassin''s Creed® III: Remastered', 15000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000010684/e3067db27e695b489f16de14d650c1c487dcf54bc9bfbbea2510f7acc9a2d57e', 'AC III Remastered te lleva a la Revolución Americana. Juega como Connor, un asesino mestizo, y lucha por la libertad. Incluye gráficos mejorados, todos los DLC y Assassin''s Creed Liberation Remastered. Vive el nacimiento de una nación con el credo.', 'https://www.youtube.com/watch?v=Ife763K1UGY', '14.7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('ASSASSIN’S CREED® THE EZIO COLLECTION', 15000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000038691/b6a394cabf523eb87c6dcae28d51dbea67991aee95e8de35de15a2b85af59500', 'The Ezio Collection recopila la trilogía completa del legendario Asesino Ezio Auditore: AC II, Brotherhood y Revelations. Revive su épico viaje en el Renacimiento en Italia. Incluye todos los DLC y cortometrajes. Una aventura de historia y venganza', 'https://www.youtube.com/watch?v=RtuAhlR994o', '7.4 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Astral Chain', 19000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000018695/76f381cf2156c793d5f7a9e5c66f4d872b593d2e9d79ed8b84eb9827f32bb655', 'Astral Chain es un hack and slash futurista desarrollado por PlatinumGames. Eres un policía de la Fuerza de Tarea especial "Neuron", que utiliza armas vivientes (Legiones) unidas por una cadena astral para combatir invasiones interdimensionales. ¡Combate cooperativo sinérgico y estilizado!', 'https://www.youtube.com/watch?v=brmmV3g4qqo', '9.8 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Batman: Arkham Trilogy', 23000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70070000018073/30648e0a24cff549fe97f586431b4b927a8e49f3531108ec50fd00a106733b4d', 'La Arkham Trilogy recopila tres obras maestras: Asylum, City y Knight. Conviértete en Batman y enfrenta a los villanos más icónicos de Gotham. Experimenta el combate FreeFlow y el sigilo del Caballero Oscuro en una saga imprescindible.', 'https://www.youtube.com/watch?v=lVMNvvaXJ2s', '48.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Bayonetta™ 3', 22500, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000046400/b8253606e02af78e2e3447748917047cae78a1c009ad7d32d1f70b2816f157b4', 'Bayonetta 3 es un espectacular hack and slash de acción. La Bruja de Umbra regresa para salvar el multiverso, enfrentándose a la nueva amenaza, los Homúnculos. Invoca demonios gigantes con el Demon Masquerade y desata el caos con estilo y nuevos poderes.', 'https://www.youtube.com/watch?v=IG19gJFgLKg', '14.5 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('BioShock The Collection', 15000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000029352/11c0cfa01694d37d55c9eae3705ba0697c2dc6b8f7f98c41ac57b39eb02a32cb', 'BioShock: The Collection incluye tres obras maestras narrativas: BioShock, BioShock 2 e Infinite. Explora las distopías de Rapture (bajo el mar) y Columbia (en el cielo). Combina shooters con poderes plasmídos y toda la experiencia DLC.', 'https://www.youtube.com/watch?v=4EDCm2syQWU', '12.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Bob Esponja The Cosmic Shake', 23000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000049285/3b5d00ecf2cf5cf70dc7309baec0b06480be1fb069d2201b82a81095a87043fd', 'En The Cosmic Shake, Bob Esponja y Patricio crean un caos que desgarra el tejido del universo. Viaja a través de siete Mundos de Deseos distintos con nuevos trajes y habilidades. Es una divertida aventura de plataformas 3D con el humor clásico de Fondo de Bikini.', 'https://www.youtube.com/watch?v=-aJ6Y-Dkyi8', '7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Borderlands 3 Ultimate Edition', 24990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000031761/dd3a887e71f07e929ed21e50112e15b43675f996c0b6c9a1e44870513fd5aa89', 'Borderlands 3 Ultimate Edition es un looter shooter RPG de acción. Elige un Buscador de la Cámara y dispara a través de planetas para detener a los Calypso Twins. Incluye el juego base y todo el contenido DLC.', 'https://www.youtube.com/watch?v=Q73UMSiMtjw', '9.4 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Borderlands Legendary', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70070000010161/6254253e0906b7ee37a5b605ea9b1bd0821ccfd66af4d29a466c2a3ed65e0a37', 'Borderlands Legendary Collection incluye tres looter shooters esenciales: Borderlands, Borderlands 2 y Borderlands: The Pre-Sequel. Sumérgete en el caótico mundo de Pandora, busca billones de armas y vive el humor negro y la acción RPG. Incluye todos los DLC.', 'https://www.youtube.com/watch?v=TdgOgMC-l40', '49 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Bravely Default II', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000028643/a1f63cce5975c248f3c69361966b38a23183959b59d3745144528a162ff5ea0d', 'Bravely Default II es un RPG clásico de fantasía. Sigue a cuatro Héroes de la Luz en su misión para recuperar los Cristales. Cuenta con el adictivo sistema de batalla "Brave y Default" y un profundo sistema de oficios (Jobs).', 'https://www.youtube.com/watch?v=DsjTKIt3z8A', '12,4 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Captain toad', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000002722/357bb5040180a8d684851fae0abf47f1baa0475c9a465375bf6d369d3102aa88', 'Captain Toad: Treasure Tracker es un divertido juego de puzles y plataformas. Gira el escenario para revelar caminos ocultos y ayuda al Capitán Toad a encontrar Estrellas de Poder. No puede saltar, ¡así que la estrategia es clave! Incluye niveles cooperativos y desafíos adicionales.', 'https://www.youtube.com/watch?v=9mNWNYelWq0', '1.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Captain Tsubasa Rise of the new Champion', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000026706/506724a303dbfe5e387bbb0994389550c6228226ebe802c2b2abc608c9b7c904', 'Captain Tsubasa: Rise of the New Champion es un juego de fútbol arcade con acción espectacular. Revive la historia de Tsubasa Ozora con tiros especiales exagerados y cinemáticas épicas. Crea tu propio personaje y participa en el modo New Hero.', 'https://www.youtube.com/watch?v=x9Xwti7ID8A', '14.9 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Crash 4 It''s about Time', 20000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000029035/52f1799d32072107f9f0ecad96fb833c4a0850b7e1cc6b1c7ca630b9f89dd2a0', 'Crash 4 es la esperada secuela directa de la trilogía original. Es un juego de plataformas 3D con un desafío clásico y moderno. Usa las Máscaras Cuánticas para alterar el tiempo y el espacio en niveles absurdamente creativos.', 'https://www.youtube.com/watch?v=ch3fBDv9Wa0', '10.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Crash Team Racing', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000016211/54604e9a2dfd69c7cacef0faf07b2189b9f31c746655590e011a533eb7f79b8d', 'Crash Team Racing Nitro-Fueled es un remake del clásico juego de carreras de karts de Crash Bandicoot. Derrapa, salta y usa potenciadores para ganar. Incluye contenido de Crash Nitro Kart y Tag Team Racing.', 'https://www.youtube.com/watch?v=5e5UoKEuz0U', '9.3 GB', false, null, true);
