insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Cuphead', 10000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000016330/d94d2186ef03c930392253c83c84af0c73b7e57cd902a526b09b4155a25930fe', 'Cuphead es un juego de acción run and gun famoso por su dificultad y su estilo visual único, inspirado en los dibujos animados de los años 30. Enfréntate a épicas y desafiantes batallas contra jefes para saldar una deuda con el Diablo.', 'https://www.youtube.com/watch?v=HEMyc7qpxjQ', '3.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Dark souls', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000008122/453d17f26995df6bd67d698c90ba2fd27157a61875e1a9730545da23474c6aaf', 'Dark Souls Remastered es el RPG de acción gótico que definió el género. Explora el vasto y lúgubre mundo de Lordran en una aventura de fantasía oscura y dificultad implacable. Domina el combate, aprende de cada muerte y forja tu destino.', 'https://www.youtube.com/watch?v=N_ISiSiYDqU', '4 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Dead By Daylight', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000016124/fe28c7ebca96e110b3dd09bfe34d11c8ac72577e25c55a435d56c34dc59aa00d', 'ead by Daylight es un multijugador asimétrico de terror 4 contra 1. Cuatro supervivientes intentan escapar de un asesino implacable en un mapa cerrado. Coopera para reparar generadores y usa el sigilo para sobrevivir.', 'https://www.youtube.com/watch?v=K42_Ed37zKg', '18.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Demon Slayer -Kimetsu no Yaiba- The Hinokami Chronicles', 19000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000048562/0b2b93a7bb41a8308347869533a28faa1dfaa1d506631b91a45e32d4e12e2833', 'The Hinokami Chronicles es un juego de lucha de arena 3D basado en el popular anime Demon Slayer. Revive la historia de Tanjiro Kamado y la búsqueda para restaurar a Nezuko. Domina las técnicas de respiración en intensos duelos 2v2.', 'https://www.youtube.com/watch?v=LuH-7ZBzZ2k', '11.1 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Detective Pikachu™ Returns', 26000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000068693/c4b5a71815eb1817733a82d6228a624751f8f4a3fbc6c3a4f69f81be1e114454', 'Detective Pikachu Returns es una aventura de misterio y puzles. Forma equipo con un Pikachu parlante y amante del café, y con Tim Goodman, para resolver extraños incidentes en Ryme City. Interroga testigos (humanos y Pokémon) y usa las pistas para descifrar el caso.', 'https://www.youtube.com/watch?v=KIJIidyLpgo', '9 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Diablo II', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000038819/353b407a48c000cc6fce107d5e0295917a97adc1c79f16dbb58a1740f2648a01', 'Diablo II: Resurrected es la remasterización del influyente action RPG. Lucha contra hordas de demonios y jefes épicos mientras persigues al Oscuro Vagabundo. Disfruta de la jugabilidad clásica con gráficos renovados, clases icónicas y hasta 4 jugadores cooperativos en portátil.', 'https://www.youtube.com/watch?v=io55tLUhV30', '8.4 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Diablo III', 15000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000012305/9d8f95e20b59b76eab1a74aaefdabbabe6438b6761efc4efa6306dde638987f3', 'iablo III: Eternal Collection es un action RPG frenético. Escoge tu clase de héroe y mata demonios para salvar Santuario. La edición de Switch incluye todo el contenido (expansión Reaper of Souls y el pack Rise of the Necromancer).', 'https://www.youtube.com/watch?v=IXXqMyyeY0c', '16.7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Digimon Cyber Sleuth', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000021089/fba74c71c47f0f480375dc973e7c80514f5ebd3f952ce16edbf02e6e39dde005', 'Digimon Story Cyber Sleuth: Complete Edition combina dos RPG japoneses. Resuelve misterios en el mundo real y el ciberespacio. Colecciona, entrena y haz evolucionar a más de 300 Digimon. Disfruta de una historia profunda y combates por turnos llenos de estrategia.', 'https://www.youtube.com/watch?v=2zY_RWXre3o', '4.9 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Digimon Next Order', 23000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000042393/eb662f39defae1a3951d64af2e92ca93600e86b07f31fe05ecc23d2c015ffcb4', 'Digimon World: Next Order es un RPG de crianza y aventura. Entrena y establece lazos con dos compañeros Digimon a la vez, explorando el Mundo Digital para salvarlo. El entrenamiento, la alimentación y el cuidado son clave para las batallas estratégicas.', 'https://www.youtube.com/watch?v=5ktRO2dz2Do', '6.7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Digimon Survive', 22000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000011733/21079a487a55a4cb7abea2f194d1887d1420e62da28fd833142fda2d9f99432b', 'Digimon Survive es una novela visual de supervivencia con elementos de RPG táctico. Un grupo de estudiantes es transportado a un mundo peligroso. Tus decisiones afectan la historia y la evolución de tus Digimon.', 'https://www.youtube.com/watch?v=j5ZsgYxKXfg', '5 GBinsert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Donkey Kong Country™ Returns HD', 26990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000084604/7f07f7a3b613185e597f72701859f58b0b6513ed8fedf35ee3048ce124ec2dca', 'Donkey Kong Country Returns HD trae el clásico de plataformas en 2D con gráficos mejorados a Switch. Juega como Donkey y Diddy Kong para recuperar el alijo de plátanos robado. Disfruta de niveles desafiantes, un modo cooperativo local y todos los niveles del original.', 'https://www.youtube.com/watch?v=aHYL0-4XrUk', '8.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Donkey Kong tropical Freeze', 21000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000001339/d01cba67eb98fec32ac98027c07fa8d92dd52773565bfadc69f817c860e34b8a', 'Tropical Freeze es un aclamado juego de plataformas 2D. Ayuda a Donkey Kong y a sus amigos a recuperar su isla congelada de los invasores. Ofrece un diseño de niveles brillante, jugabilidad desafiante y la adición del modo Funky Kong, que facilita la experiencia para nuevos jugadores.', 'https://www.youtube.com/watch?v=1psp2t0Zi9o', '6.7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Donkey Kong™ Bananza', 35000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/store/software/switch2/70010000096809/5420893af8eee86d1e49bbf5ed445b991053e6650c28024bc9bb98333d31624c', 'Donkey Kong Bananza es una aventura de plataformas 3D para Nintendo Switch 2. Controla a Donkey Kong en un vasto mundo subterráneo con Pauline. El juego enfatiza la destrucción del entorno, permitiéndote abrirte camino a puñetazos y excavar para explorar y encontrar secretos.', 'https://www.youtube.com/watch?v=wxCQ2Ht_UKA', '8.9 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Doom (2016)', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000001367/800b512924c41501b2c4a58f573beabf66565266747d6fe94bf7e138f0308f6a', 'DOOM (2016) es un frenético shooter en primera persona. Eres el DOOM Slayer y tu misión es acabar con la invasión demoníaca en Marte y el Infierno. Disfruta de combate brutal, armas devastadoras y el sistema "Glory Kill" para ejecutar a tus enemigos.', 'https://www.youtube.com/watch?v=6lRpoGucGA0', '22 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Doom Eternal', 20000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000018023/09fde58766118f7aec9f6ff30f3a8d6e7ba37ace336e79097643431c911d99c1', 'DOOM Eternal es la secuela del shooter de 2016, llevando el combate a un nivel superior. Regresa como el DOOM Slayer para salvar la Tierra de los demonios con un arsenal masivo y un sistema de recursos estratégicos ("push forward combat").', 'https://www.youtube.com/watch?v=2wdW0HB_NhM', '33 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Dragón Ball FighterZ', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000006225/c54b2f3d57ca5759d5f7775f3054fd208b47839345c8fb82aabfbbdffa657683', 'Dragon Ball FighterZ es un juego de lucha 2D por equipos de 3 contra 3, desarrollado por Arc System Works. Presenta gráficos alucinantes que replican el anime a la perfección. Domina combos rápidos, movimientos especiales y espectaculares Supers.', 'https://www.youtube.com/watch?v=VsK6DgwqMnU', '10 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Dragón Ball Kakarot', 19000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000035337/0f435287e9645b319b2d27acd5b9454b286c91c6c7efaa010d4ee098a38d5c3d', 'Dragon Ball Z: Kakarot es un RPG de acción que revive la épica historia de DBZ, desde la Saga Saiyan hasta la de Buu. Juega como Goku y otros personajes, explora un vasto mundo abierto, pesca y entrena.', 'https://www.youtube.com/watch?v=BCqSFITX6kI', '21.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Dragón Ball Xenoverse 2', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000001144/b1a1b3f23de2aa67b2498d06d45b6c2fca75b6d3015c9a1d0804a5c69a2f7c74', 'Dragon Ball Xenoverse 2 es un RPG de acción con batallas 3D. Crea tu propio Patrullero del Tiempo para proteger la historia de DB. Entrena con personajes icónicos, aprende sus técnicas y participa en combates masivos y voladores.', 'https://www.youtube.com/watch?v=H1z7YY7AHRI', '10.8 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Dying Light: Definitive Edition', 21000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000032722/65d250af4879add6222b7b874d53122af6f769b0e402729759444b46b216b944', 'Dying Light: Definitive Edition es un juego de acción y supervivencia en primera persona. Combina parkour fluido con combate brutal contra zombis. Explora la ciudad de Harran y sobrevive a la noche, cuando los infectados se vuelven más letales.', 'https://www.youtube.com/watch?v=r7HAp6N6gMk', '16.5 GB', false, null, true);
