insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('EA SPORTS FC™ 26', 28000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000091347/a4ce113ce08d7c7a94e50dc5104ea74a90fcb3c7d6b465fb8a1524b3df012e09', 'EA SPORTS FC™ 26 eleva la simulación de fútbol en Switch. Disfruta de la acción realista con equipos y ligas globales. El juego introduce una IA táctica avanzada y nuevos eventos de Ultimate Team. Construye tu equipo soñado o lleva a tu club a la gloria en el modo Carrera mejorado.', 'https://www.youtube.com/watch?v=giWPBsPsZ1M', '31.7 GB', false, null, true);
