insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Ea Sports Fifa 2022', 15000, 'https://assets.nintendo.com/image/upload/c_fill,w_1200/q_auto:best/f_auto/dpr_2.0/ncom/software/switch/70010000038676/02b078ec6e65f597dc655c1b958bf2dd07961ea45db4d59688ca8746bf28ae6d', 'A SPORTS FIFA 22 es una Legacy Edition que actualiza las plantillas y uniformes a la temporada 2021/2022. Conserva las características y la jugabilidad de ediciones anteriores, enfocándose en ofrecer una experiencia futbolística portátil con los modos Carrera y Ultimate Team.', 'https://www.youtube.com/watch?v=o1igaMv46SY', '5.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Ea Sports Fifa 2023', 16000, 'https://www.nintenderos.com/wp-content/uploads/2022/07/FIFA-23..-Legacy-Edition.jpg', 'EA SPORTS FIFA 23 en Switch es una Legacy Edition que ofrece las últimas plantillas de la temporada 2022/2023. Incluye nuevos uniformes y clubes, y por primera vez, añade la Copa Mundial Femenina y la Copa Mundial de la FIFA Catar 2022.', 'https://www.youtube.com/watch?v=o3V-GvvzjE4', '5.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Everybody Switch 1-2', 19000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000068159/de4985f3b03b7b50565be4b906ded22186f8365cc8c25bcbe1ed76882df39a17', 'verybody 1-2-Switch! es la secuela del party game, con foco en juegos grupales y usando tanto Joy-Cons como teléfonos inteligentes (¡hasta 100 jugadores!). Participa en desafíos por equipos o minijuegos rápidos. Ideal para grandes reuniones.', 'https://www.youtube.com/watch?v=C3XCaPkBBYw', '3.4 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Fire Emblem Engage', 23000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000058802/88b8db494399e659522af36331b7f588439bc4312af5c0ee57035c063651ab4a', 'Fire Emblem Engage es un RPG táctico por turnos donde el héroe, Alear, despierta para restaurar la paz. Invoca a héroes de juegos anteriores (Emblems) para obtener sus habilidades en combate. Disfruta de batallas estratégicas profundas y personaliza tus unidades.', 'https://www.youtube.com/watch?v=DMtDNA_kiZ4', '16.6 GB', false, null, true);
