insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Grand Theft Auto Trilogy Definitive Edition', 23000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70070000013113/05298f2186ad985b8d943597e8fb3df4ad0c79363f7b290ecc38816036f2a49a', 'GTA Trilogy reúne tres clásicos de mundo abierto: GTA III, Vice City y San Andreas. Disfruta de la acción criminal y la libertad de exploración con mejoras visuales y de jugabilidad específicas para Switch.', 'https://www.youtube.com/watch?v=D71cBUeAL58', '22.7 GB', false, null, true);
