insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Howgarts Legacy', 24990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000014724/72ce0a17215521a167c3da579db4cc48a2f7a52eacc81ad985ba20fd6817fdc2', 'Hogwarts Legacy es un RPG de acción ambientado en el mundo mágico del siglo XIX. Crea a tu propio estudiante y vive tu vida en Hogwarts. Asiste a clases, aprende hechizos, haz amigos y descubre secretos ocultos.', 'https://www.youtube.com/watch?v=AbcVn-epOFY', '14.5 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('It Takes Two', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70070000014924/e7200824041808289d4a65589ed368f7e08dc2e538a5fd7ee9f8d39e58015c24', 'It Takes Two es una aventura de plataformas cooperativa obligatoria. Juega con un amigo (local o en línea) como Cody y May, una pareja transformada en muñecos. Superen desafíos de plataformas y puzles en un viaje mágico que explora temas de relaciones y trabajo en equipo.', 'https://www.youtube.com/watch?v=s-i_ys7VauE', '9.5 GB', false, null, true);
