insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Jump force', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70070000011045/003a40f7fdb41cdf489fdfd82caf4e62104926ee4f731cc71d3758a94f8099ea', 'Jump Force es un juego de lucha 3D que une a héroes y villanos de Shonen Jump (Dragon Ball, One Piece, Naruto, etc.). Crea tu avatar y lucha para salvar el mundo real de una amenaza. Desata superpoderes en batallas épicas 3 contra 3.', 'https://www.youtube.com/watch?v=UnGPPgb3AEE', '163 MB', false, null, true);
