insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Sonic Frontiers', 21000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000040331/96118506c3829370249225b8e82f1ae061036bdcf337b0265258efe1f8cf3bd9', 'Splatoon 3 lleva la acción de entintado a la región de Tintelia. El shooter 4 vs 4 se expande con nuevos movimientos, armas y el modo Guerra Territorial. Disfruta del modo cooperativo Salmon Run (ahora disponible 24/7) y de una nueva y extensa campaña en el modo El Regreso de los Mamíferos.', 'https://www.youtube.com/watch?v=vDLVWWJ0nxg', '15.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Sonic Manía', 13000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000000809/2292c70c99e9a181e9e3a60f42961da13a9e80e5178954bb8c42f5ffda379849', 'Battle for Bikini Bottom - Rehydrated es un remake del clásico plataformas de Bob Esponja. Juega como Bob Esponja, Patricio y Arenita para detener el ejército de robots de Plankton. Disfruta de gráficos modernos y contenido multijugador restaurado. ¡Un juego de plataformas 3D divertido y fiel al original!', 'https://www.youtube.com/watch?v=ft03IjKchoM', '390 MB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('SONIC X SHADOW GENERATIONS', 28000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000069536/62d840ef779d25a962d0a7710a5b3e46e27df886bcfba7997ee65395da7efaac', 'Spyro Reignited Trilogy incluye los tres juegos originales de plataformas de PlayStation (Spyro the Dragon, Ripto''s Rage! y Year of the Dragon) completamente remasterizados. Juega como el dragón Spyro y usa tu aliento de fuego y tus embestidas para salvar los Reinos del Dragón.', 'https://www.youtube.com/watch?v=btget8Gphdw', '14.7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Splatoon™ 2', 15000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000000529/b0b183a9860296016649fadb03b929411e7e5e0809af241e2e9652ebf0c5a715', 'uper Mario 3D All-Stars es una colección que incluye tres clásicos de Mario en 3D: Super Mario 64, Super Mario Sunshine y Super Mario Galaxy. Disfruta de la acción plataformera en 3D con gráficos actualizados. Incluye también los soundtracks completos de los tres juegos.', 'https://www.youtube.com/watch?v=CPJcaGWoO2c', '6.1 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Splatoon™ 3', 21000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000046395/4555efa9f2061f7d1e1646ab3d3af790a7491270b1b3e32e730273e9ac096827', 'uper Mario Galaxy + Super Mario Galaxy 2 es una colección de las dos aclamadas aventuras espaciales de plataformas 3D. Explora planetas esféricos, usa potenciadores como Mario Abeja y Mario Nube, y únete a Yoshi en Galaxy 2.', 'https://www.youtube.com/watch?v=-hwwbFnhICQ', '7.5 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('SpongeBob SquarePants: Battle for Bikini Bottom', 15000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000027153/274f38c621d08611ac55067e5446fa70c2091127cb2f6ef0c34ee4c5a3802f00', 'Super Mario Maker 2 te permite crear y jugar niveles de Mario infinitos. Usa herramientas intuitivas para diseñar stages en estilos de juegos clásicos y el nuevo Super Mario 3D World. Disfruta del modo historia con más de 100 niveles de Nintendo y comparte tus creaciones en línea con la Comunidad Mundial de Niveles.', 'https://www.youtube.com/watch?v=js33zxhyFfc', '11.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Spyro™ Reignited Trilogy', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000019384/49a855384aa8569dc6b8fe961cb358a7dc161f55204b0b1cfad226a6a0871891', 'Super Mario Odyssey es una aventura de plataformas en 3D de mundo semiabierto. Mario viaja entre reinos a bordo de la nave Odyssey para salvar a Peach de Bowser. Usa a Cappy, la gorra mágica, para capturar enemigos y objetos, y usar sus habilidades únicas.', 'https://www.youtube.com/watch?v=5kcdRBHM7kM', '15.1 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario 3D All-Stars', 18000, 'https://www.nintendo.com/eu/media/images/10_share_images/games_15/nintendo_switch_4/H2x1_NSwitch_SuperMario3DAllstars_image1600w.jpg', 'Super Mario Party trae de vuelta el clásico juego de mesa y minijuegos. Juega con dados únicos de cada personaje y compite en más de 80 minijuegos nuevos. Incluye modos cooperativos, desafíos rítmicos y el innovador Toad''s Rec Room, que usa dos consolas Switch. ¡Diversión garantizada para hasta 4 jugadores!', 'https://www.youtube.com/watch?v=D7zTJLIYJds', '5 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario Galaxy™ + Super Mario Galaxy™ 2', 36000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/store/software/switch/70070000030770/0acaf709e29c57e125e90032853562562843757d238fec2815a52ec0409c6fd1', 'Super Mario Party Jamboree es la mayor entrega de la saga. Compite en más de 110 minijuegos y cinco nuevos tableros. Juega en el Parque Acuático Koopa y disfruta del nuevo modo competitivo para 20 jugadores en línea: Bowserathlon. Incluye un modo juego de mesa simplificado.', 'https://www.youtube.com/watch?v=iEl4bn8q6gc', '7.7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario Maker™ 2', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000018694/aac100206f1c50349fd2c48595e55603259ae60a4ab4eefc28e71f41efb78b97', 'Super Mario RPG es el remake del primer RPG de Mario. Únete a Mario, Bowser, Peach y dos nuevos aliados, Mallow y Geno, para reparar la Vía Estelar rota. Disfruta del combate por turnos con comandos de tiempo y gráficos 3D completamente renovados. ¡Una aventura clásica de Square Enix y Nintendo!', 'https://www.youtube.com/watch?v=0r5PJx7rlds', '3.1 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario Odyssey™', 21000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000001130/c42553b4fd0312c31e70ec7468c6c9bccd739f340152925b9600631f2d29f8b5', 'Mario Strikers: Battle League es un frenético juego de fútbol callejero 5 vs 5 sin reglas, ambientado en el universo de Mario. Usa objetos y devastadores Hiperchuts para marcar goles. Personaliza a tus personajes con equipamiento que altera sus estadísticas. ¡Juega localmente o únete a un Club Strikers en línea!', 'https://www.youtube.com/watch?v=cLAzzYz92r4', '5.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario Party™', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000014158/0ca41128bf40b7e0dc32a046a659ecdc69e4d7cc7a3257d6280be665d2f795b5', 'Super Mario Bros. Wonder es un plataformas 2D con un enfoque en la sorpresa. Juega como Mario, Luigi, Peach, Daisy o Toad, y usa la Flor Maravilla para transformar los niveles de forma inesperada (tuberías que caminan, personajes que cambian de forma). El nuevo potenciador Elefante añade diversión.', 'https://www.youtube.com/watch?v=JStAYvbeSHc', '2.9 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario Party™ Jamboree', 27990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000084608/ba0572bf9d840b03bf9958809943fb3c76c3adfd6d8f2704b0f1b766f8aa4027', 'Super Mario 3D World + Bowser’s Fury incluye el clásico plataformas 3D con multijugador cooperativo (hasta 4 jugadores) y el nuevo modo Bowser''s Fury. En 3D World, usa el potenciador Traje Felino. En Bowser''s Fury, Mario explora un mundo abierto junto a Bowsy para detener a un Bowser gigante y furioso.', 'https://www.youtube.com/watch?v=OPAQA_P_RQY', '5.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario RPG™', 25990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000068683/fe4afe940b0e707798332e86f0af56cdbde48da59dc37cdfb8d59febb88ac72a', 'Super Smash Bros. Ultimate es el crossover de lucha definitivo. Cuenta con más de 80 personajes jugables y todos los personajes de la historia de Smash. Compite en combates de hasta 8 jugadores y domina el modo Mundo de Estrellas Perdidas (campaña para un jugador). ¡Incluye cientos de escenarios y música de videojuegos!', 'https://www.youtube.com/watch?v=JaZ80mfhnhI', '6.5 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario Striker', 23000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000049936/a2f2110d63e18a774199c31dceb310a562b0d8d072c7b4a92dd4faa36f1bfc71', 'Team Sonic Racing es un juego de carreras de karts centrado en el juego en equipo. Corre con personajes de Sonic y usa movimientos cooperativos para potenciar a tus compañeros. Disfruta de varios modos de juego, incluyendo la campaña para un jugador y el multijugador en línea/local. ¡La clave es la coordinación del equipo!', 'https://www.youtube.com/watch?v=PUSYm807tiU', '2.8 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario Wonder', 24990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000068688/1c5583f6bbce5bccdc923c25c35ba8f42128b55df84f4a2fbeea74b6d1d1516e', 'Terraria es una aventura de sandbox 2D que combina elementos de exploración, construcción y combate. Crea, excava y lucha en un vasto mundo generado proceduralmente. Recolecta recursos para construir bases, armas y armaduras. Enfréntate a más de 400 enemigos y bosses.', 'https://www.youtube.com/watch?v=9DwRYw2g9Sc', '3.6 GB', true, 17990, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Mario™ 3D World + Bowser’s Fury', 20000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000034439/ccb69a8bf2746b2dc0a9b11a9e48c9893baa1631486326f0d681b7a36385221f', 'The Binding of Isaac: Repentance es la edición definitiva del roguelike de disparos y mazmorras. Juega como Isaac, explorando el sótano generado proceduralmente mientras lloras para atacar. Incluye más de 700 objetos, nuevos personajes, caminos y bosses, ofreciendo cientos de horas de rejugabilidad brutal.', 'https://www.youtube.com/watch?v=A_C90i1jVzY', '3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Super Smash Bros Ultimate', 16990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000012332/ac4d1fc9824876ce756406f0525d50c57ded4b2a666f6dfe40a6ac5c3563fad9', 'The Elder Scrolls V: Skyrim es el épico RPG de mundo abierto. Juega como el Dovahkiin (Sangre de Dragón) y explora la vasta región de Skyrim en una misión para detener al dragón Alduin. Domina la magia, el combate y los Gritos de Dragón. Incluye contenido extra y controles por movimiento exclusivos de Switch.', 'https://www.youtube.com/watch?v=JSRtYpNRoN0', '17.3 GB', true, 14990, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Team Sonic Racing', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000005062/fd89756d29d1f62bcda1f096e48070f1a19e3f503c0aeb86efc2323786cbcc63', 'Hyrule Warriors: La Era del Cataclismo es un juego de acción musou que sirve como precuela de Breath of the Wild. Experimenta la Gran Calamidad 100 años antes, controlando a Link, Zelda y los cuatro Elegidos. Lucha contra hordas de enemigos en combates masivos y descubre la historia detrás de la caída de Hyrule.', 'https://www.youtube.com/watch?v=uDMWRRAEogs', '7.1 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Terraria', 12000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000001702/dac3a26570b5ca1ddf703bf0add7cc7c527f71a2b56521baf69e20c7a573c610', 'The Legend of Zelda: Breath of the Wild es un épico juego de aventura y mundo abierto. Explora el vasto reino de Hyrule con total libertad, resolviendo puzles, cazando y usando la Tabla Sheikah. Link debe recuperar sus recuerdos y derrotar a Ganon del Cataclismo. Disfruta de la física realista y la exploración orgánica.', 'https://www.youtube.com/watch?v=zw47_q9wbBE', '455 MB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Binding of Isaac: Repentance', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70050000031296/71f9ec7c254eb31488fc58db0ccc5c9a520b080dfca548eb035095dc9d1b6ecc', 'Hyrule Warriors: Definitive Edition es un musou de acción que combina The Legend of Zelda con combates de hordas masivas. Controla a más de 29 personajes (Link, Zelda, Ganondorf, etc.). Esta edición incluye todo el contenido DLCde las versiones de Wii U y 3DS, modos cooperativos y gráficos mejorados.', 'https://www.youtube.com/watch?v=DUzdlDiFUyU', '1 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Elder Scrolls V: Skyrim', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000001369/3a41386d4b0999365727a21cc5c13853cfc244abca39b689bb79a339601e48c3', 'The Legend of Zelda: Link''s Awakening es un remake del clásico de Game Boy. Link naufraga en la misteriosa Isla Koholint y debe despertar al Pez Viento para poder escapar. Disfruta de una perspectiva top-down, una historia nostálgica y el nuevo Constructor de Mazmorras. Cuenta con encantadores gráficos modernos de estilo toy-like.', 'https://www.youtube.com/watch?v=PtC6U8hOZTk', '12.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Legend of the Zelda Age Of Calamity', 16000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000034760/655ee297a993058234742a93050db5e07554c5c69c2eb9ad1dd408976ab733c3', 'The Legend of Zelda: Skyward Sword HD es la versión remasterizada del juego de Wii. Descubre el origen de la Espada Maestra en la aventura de Link, que viaja entre Celéstea (el mundo flotante) y la superficie. Disfruta de controles por movimiento mejorados o el nuevo esquema de control con botones.', 'https://www.youtube.com/watch?v=r7qozxgX4c8', '11.1 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Legend of the Zelda Breath Of the Wild', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000000025/7137262b5a64d921e193653f8aa0b722925abc5680380ca0e18a5cfd91697f58', 'The Legend of Zelda: Tears of the Kingdom es la secuela directa de Breath of the Wild. Explora un Hyrule expandido que incluye Islas Celestes y profundas Cavernas. Link usa nuevas habilidades como la Ultramano (para construir y fusionar) y la Infiltración para resolver puzles y detener una nueva amenaza.', 'https://www.youtube.com/watch?v=uHGShqcAHlQ', '14.4 GB', true, 14100, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Legend of the Zelda Hryule Warriors Definitive Edition', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000006023/4b035b357b10e59dce73609dd071e61d131d90b2e477c29088f26fbe50b44d1b', 'The Legend of Zelda: Echoes of Wisdom es la nueva aventura top-down donde Zelda es la protagonista jugable. Link ha desaparecido. Usa el poder de Trirod para crear y replicar objetos (Ecos), como bloques, enemigos y agua. Resuelve puzles y combate para salvar el reino de Hyrule y encontrar a Link.', 'https://www.youtube.com/watch?v=94RTrH2erPE', '12.9 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Legend of the Zelda Link''s Awakening', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000020033/df825d5fc6747b66b051f5d3ba6a412fe625ea7878b6a10c93bb8312195682b1', 'The Witcher 3: Wild Hunt es un épico RPG de mundo abierto. Juega como Geralt de Rivia, un cazador de monstruos a sueldo. Explora vastos reinos, toma decisiones morales con consecuencias, y embárcate en la búsqueda de Ciri. Esta versión incluye las expansiones Hearts of Stone y Blood and Wine.', 'https://www.youtube.com/watch?v=Ql2BJiDg7hY', '5.9 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Legend of the Zelda Skyward Sword', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000038612/63595b0826bb6ece7b95e4eb2a33e5ad0559224b350a5e2974a44f772963ae59', 'Tomb Raider I-III Remastered incluye los tres juegos clásicos de Lara Croft (Tomb Raider I, II y III) con todos sus packs de expansión. Vive la acción plataformera y la exploración de puzles en 3D. Disfruta de la opción de cambiar entre gráficos clásicos y modernos en tiempo real. ¡La trilogía que definió un género!', 'https://www.youtube.com/watch?v=LagLcro52Ls', '7.1 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Legend of Zelda Tears of Kingdom', 20000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000063714/956c12eb1a4c9e68b494cca7efd23d20ba8a789a5eb02589affae64bc6bc3282', 'Tony Hawk''s Pro Skater 1 + 2 es una fiel remasterización de los dos primeros juegos de skate de la saga. Revive la acción arcade con gráficos 4K/60fps (en otras plataformas; en Switch la calidad varía), todos los niveles clásicos y el elenco original de skaters. Crea tu propio skater y domina los tricks clásicos y modernos.', 'https://www.youtube.com/watch?v=bgGeMuyz7rg', '16.3 GB', true, 14990, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Legend of Zelda™: Echoes of Wisdom', 27990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000084618/e3a49cf14180cec09c515595fb7121b048a0f8327eae2d248909d0f0c64a9dc9', 'Triangle Strategy es un RPG táctico que sigue la historia de Serenoa Wolffort durante la Guerra de la Sal y el Hierro. El juego se centra en tomar decisiones morales cruciales (Justicia, Moralidad y Libertad) que afectan la narrativa y el reclutamiento de aliados. Disfruta de intensos combates tácticos por turnos con entornos 3D.', 'https://www.youtube.com/watch?v=7nhTJ-Evv_U', '5.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('The Witcher 3', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000020983/326d245efb39160ec86f1f48f7808179033b0d1ddef655b85510eb993c1ec1dd', 'Ultra Street Fighter II trae el clásico juego de lucha a Switch. Incluye a todos los personajes de Super Street Fighter IImás dos nuevos: Evil Ryu y Violent Ken. Disfruta de dos estilos gráficos (clásico pixel art o moderno HD) y el modo cooperativo "Dúo de Luchadores". ¡Perfecto para combates portátiles!', 'https://www.youtube.com/watch?v=L3zRerKA6hQ', '24.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Tomb Raider I-III Remastered Starring Lara Croft', 22000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000068310/5b849c87f8f84b92797cf7d1d04b4d3f9604fe12d8a4040e128c33112878ba5f', 'WarioWare: Get It Together! es el primer juego de la saga donde controlas activamente a Wario y sus amigos dentro de los microjuegos. Completa cientos de microjuegos ridículos en segundos. Cada personaje tiene una habilidad de movimiento única. Incluye multijugador cooperativo y competitivo para hasta 4 jugadores.', 'https://www.youtube.com/watch?v=Od0RTB_k73w', '6.6 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Tony Hawk Pro Skater 1+2', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000026221/118037085bd3dbeca6655d13a4182e32ee107fa2dd5276deb9130b915bc4b3f7', 'WarioWare: Move It! es una fiesta de microjuegos basados en el movimiento. Usa los Joy-Con y adopta docenas de posturas ridículas, llamadas "Formas", para superar más de 200 microjuegos absurdos. Incluye modos de fiesta multijugador y una aventura de historia cómica en una isla tropical.', 'https://www.youtube.com/watch?v=z4kkqicAeG0', '12.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Triangle Strategy', 19000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000046322/6d98673fdc6c558eef98cb0758e9b6d815dc088bb911e834fb91e3fa08fc7b46', 'Xenoblade Chronicles: Definitive Edition es un RPG épico. Explora los cuerpos colosales de dos titanes congelados: Bionis y Mechonis. Juega como Shulk y usa la espada Monado para luchar contra los Mekon. Disfruta de una historia profunda, un vasto mundo abierto y un epílogo adicional (Futuros Conectados).', 'https://www.youtube.com/watch?v=KfjVIQug6_E', '7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Ultra Street Fighter II', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000000185/d551d617dcbe3fc6827019eb3a8ce7a233e7f16c32687eedb3780085ff425db7', 'Xenoblade Chronicles 2 es un épico JRPG de fantasía. Explora el mundo de Alrest, un mar de nubes poblado por colosales titanes. Juega como Rex, un Piloto, que se une a la Blade legendaria Pyra/Mythra (Aegis). Disfruta de un sistema de combate rápido y profundo, y una emotiva historia sobre la amistad.', 'https://www.youtube.com/watch?v=sJuiTw6nk7A', '2.8 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('WarioWare™: Get It Together!', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000042929/ae4cfa387a655265e12fb41c45f421a6172d3f06b838c97164e67b3c082a33e8', 'Xenoblade Chronicles 3 une los mundos de los juegos anteriores en el reino de Aionios, devastado por la guerra entre las naciones de Keleves y Agnus. Seis soldados se unen para descubrir la verdad. El sistema de combate permite que los personajes se fusionen temporalmente en poderosos Urboros. ¡Un JRPG con una escala épica y emocionantes revelaciones!', 'https://www.youtube.com/watch?v=t-iNpDKuYb8', '1.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('WarioWare™: Move It!', 24990, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000068678/5b072b55e8a6993071b4cde9f74d9cf7aeac0b52141177efed6c8ce9b580a435', 'Yoshi''s Crafted World es un plataformas 2.5D con un encantador estilo visual de manualidades y cartón. Juega como Yoshi y atraviesa niveles con elementos reciclados y objetos cotidianos. Lanza huevos para encontrar secretos y resuelve puzles invirtiendo el nivel para ver el "lado B".', 'https://www.youtube.com/watch?v=k9xHZXiLvLY', '1.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Xenoblade Chronicles', 17000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000029711/d55f4d73ad88beed1ea061aaaacbe772e40f46b598db513f3f85369d3455aa82', null, null, '13.7 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Xenoblade Chronicles 2', 18000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000000707/4cd12c9f2233dc671d0ac2bc208f8551d1d0b62c956d6d477585bb42c1ef09ea', null, null, '13.2 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Xenoblade Chronicles 3', 22000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000053336/e933b48650b33b355e9cf2583da5c94b77180e40fb02d050041083dd62f4df39', null, null, '14.3 GB', false, null, true);
insert into public.games (title, price, image_url, description, trailer_url, storage_required, is_offer, offer_price, is_active) values ('Yoshi''s Crafted World', 20000, 'https://assets.nintendo.com/image/upload/ar_16:9,c_lpad,w_1240/b_white/f_auto/q_auto/ncom/software/switch/70010000000734/d6d49ad8d59a5bd170c96b40c934fc537c613d10e7a43f42154084b75a18955f', null, null, '5.6 GB', false, null, true);
insert into public.pack_items (pack_id, title, sort_order) select new_pack.id, item.title, item.sort_order from new_pack, (values ('Pokémon Scarlet', 0), ('Pokémon Legends: Arceus', 1), ('Pokémon Sword + DLC', 2), ('Pokémon: Let''s Go, Eevee!', 3), ('The Legend of Zelda: Breath of the Wild', 4), ('Sid Meier''s Civilization VI', 5)) as item(title, sort_order);
insert into public.pack_items (pack_id, title, sort_order) select new_pack.id, item.title, item.sort_order from new_pack, (values ('New Super Mario Bros. U Deluxe', 0), ('Mario Kart 8 Deluxe', 1), ('Five Nights at Freddy''s', 2), ('DOOM', 3), ('SEGA AGES SONIC THE HEDGEHOG', 4)) as item(title, sort_order);
insert into public.pack_items (pack_id, title, sort_order) select new_pack.id, item.title, item.sort_order from new_pack, (values ('The Legend of Zelda: Echoes of Wisdom', 0), ('The Legend of Zelda: Link''s Awakening', 1), ('The Legend of Zelda: Skyward Sword HD', 2), ('Pokémon Scarlet', 3), ('Pokémon Legends: Arceus', 4), ('Subnautica Below Zero', 5), ('Subnautica', 6), ('Trove', 7), ('Slime Rancher: Plortable Edition', 8), ('Spellbreak', 9), ('Minecraft Dungeons + dlc', 10), ('Hollow Knight', 11), ('Pokémon Sword | only dlc', 12), ('The Legend of Zelda: Breath of the Wild | only dlc', 13)) as item(title, sort_order);
